import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { flare } from '@flareapp/js';
import { FlareErrorBoundary } from '@flareapp/react';

flare.configure({
    reportingUrl: 'https://ingress-staging.flareapp.io/api/reports',
});
flare.light();

if (typeof window !== 'undefined') {
    window.flare = flare;
}

const buttonStyle = {
    padding: '10px 18px',
    backgroundColor: '#e74c3c',
    color: 'white',
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '14px',
    marginRight: '0.5rem',
    marginBottom: '0.5rem',
};

const cardStyle = {
    border: '1px solid #e5e7eb',
    borderRadius: '8px',
    padding: '1rem 1.25rem',
    margin: '0.75rem 0',
    textAlign: 'left',
    backgroundColor: '#fafafa',
};

function runFlareTest() {
    flare.test();
}

function thirdLevelExplode(payload) {
    const nothing = null;
    return nothing.shouldNotExist(payload);
}

function secondLevelCompute(payload) {
    return thirdLevelExplode(payload) + 1;
}

function DeeplyNestedTrigger() {
    const onClick = () => {
        secondLevelCompute({ user: 'alex', source: 'DeeplyNestedTrigger' });
    };

    return (
        <button style={buttonStyle} onClick={onClick}>
            Trigger deeply nested TypeError
        </button>
    );
}

function AsyncPromiseTrigger() {
    const onClick = async () => {
        await Promise.resolve();
        const data = JSON.parse('{ this is not json');
        console.log(data);
    };

    return (
        <button style={buttonStyle} onClick={onClick}>
            Trigger async SyntaxError
        </button>
    );
}

function ManualReportTrigger() {
    const onClick = () => {
        try {
            const obj = undefined;
            obj.nope();
        } catch (error) {
            flare.report(error, { trigger: 'ManualReportTrigger' });
        }
    };

    return (
        <button style={buttonStyle} onClick={onClick}>
            Catch + flare.report()
        </button>
    );
}

function RenderCrashChild({ shouldCrash }) {
    if (shouldCrash) {
        const items = null;
        return <div>{items.map((item) => item)}</div>;
    }
    return <div>Child renders fine until you flip the switch.</div>;
}

function RenderCrashParent() {
    const [crash, setCrash] = useState(false);

    return (
        <div>
            <button style={buttonStyle} onClick={() => setCrash(true)}>
                Trigger render-time crash (boundary catches it)
            </button>
            <RenderCrashChild shouldCrash={crash} />
        </div>
    );
}

function FlareTestTrigger() {
    return (
        <button style={{ ...buttonStyle, backgroundColor: '#2563eb' }} onClick={runFlareTest}>
            Run flare.test()
        </button>
    );
}

function App() {
    return (
        <div style={{ maxWidth: '720px', margin: '2rem auto', padding: '0 1rem', fontFamily: 'system-ui, sans-serif' }}>
            <h1>Flare frontend error playground</h1>
            <p>
                This page exercises the sourcemap integration with a handful of nested components and error shapes.
                Open the browser devtools and click a button; the resulting report should show up in Flare staging with
                a de-minified stack trace pointing back into the <code>resources/js/frontend-errors.jsx</code> sources.
            </p>

            <div style={cardStyle}>
                <h3>Verify the setup</h3>
                <FlareTestTrigger />
            </div>

            <div style={cardStyle}>
                <h3>Deeply nested synchronous error</h3>
                <p>Three function frames deep, inside an event handler.</p>
                <DeeplyNestedTrigger />
            </div>

            <div style={cardStyle}>
                <h3>Async error after an await</h3>
                <p>Thrown after a microtask — exercises async stack handling.</p>
                <AsyncPromiseTrigger />
            </div>

            <div style={cardStyle}>
                <h3>Manually reported caught error</h3>
                <p>Caught with try/catch and sent via <code>flare.report()</code>.</p>
                <ManualReportTrigger />
            </div>

            <div style={cardStyle}>
                <h3>Render-phase crash (FlareErrorBoundary)</h3>
                <p>Child throws during render; the boundary catches and reports it.</p>
                <RenderCrashParent />
            </div>
        </div>
    );
}

const container = document.getElementById('frontend-errors-app');
if (container) {
    createRoot(container).render(
        <FlareErrorBoundary>
            <App />
        </FlareErrorBoundary>,
    );
}
